INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989332","title":"Боун. Том 5. Кремень, хозяин восточной границы","author":"Джефф Смит","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002190959/140/7282/Dzheff_Smit__Boun._Tom_5._Kremen_hozyain_vostochnoj_granitsy.jpg","isbn":"978-5-9906529-8-9","publisher":"Рамона","pubDate":"2017","language":"Русский","series":"Боун","genres":[],"annotation":"Провожая детёныша крысьих созданий в горы, Фоун Боун и Смайли Боун встречают хитрого и могучего горного льва по имени Кремень. Кремень называет себя хозяином восточной границы и не очень жалует объявившихся в его владениях незваных гостей. Всё становится ещё сложнее, когда наши герои находят развалины древнего храма.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999154,"hdCover":""},{"id":"0989331","title":"Боун. Том 4. Охотник на Драконов","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002020905/140/7fde/Dzheff_Smit__Boun._Tom_4._Ohotnik_na_Drakonov.jpg","isbn":"978-5-9906529-7-2","publisher":"Рамона","pubDate":"2016","language":"Русский","series":"Боун","genres":["Комиксы","манга","графические романы"],"annotation":"Сюжет «Боуна» начинается незамысловато, но по мере развития серии раскручивается до масштабного эпика в духе «Властелина Колец».  Изгнанная из Боунвиля троица двоюродных братьев (Фоун Боун, Фоуни Боун и Смайли Боун) разделилась и заблудилась в бескрайней неизведанной пустыне. Независимо друг от друга, они находят свой путь в таинственную, покрытую лесом долину, заселённую прекрасными и ужасными созданиями.  Что делать, если коварнейшим врагом наших героев является ни кто иной, как сам Фоуни Боун? Этому прохвосту удаётся обмануть всех жителей посёлка и выдать себя за могучего охотника на драконов.  Человек в капюшоне готовит свою огромную армию к полномасштабной войне. Кто-то продолжает преследовать Торн во снах. Мудрая бабушка Бен внезапно исчезает. А Фоуна Боуна и его спутников ждёт страшная встреча с Кингдоком...  На данный момент этот комикс собрал 44 международные награды, не говоря уже о 10 премиях Айснера и 11 премиях Харви, и продолжает попадать в топы рекомендованных комиксов для всех возрастов. «Боун» издаётся в 28 странах, только в США было распродано более 6 миллионов экземпляров.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999153,"hdCover":""},{"id":"0989330","title":"Лига справедливости. Книга 1. Начало","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001202163/140/adf1/Dzheff_Dzhons__Liga_spravedlivosti._Kniga_1._Nachalo.jpg","isbn":"978-5-389-09719-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Величайшие герои мира… впервые объединяются в команду! Мир стоит на пороге новой эры – эры супергероев. Но человечество пока не привыкло к этой мысли. Далеко не всем это нравится, что среди нас живут люди, обладающие невероятными способностями. Но однажды Земля сталкивается с угрозой слишком серьезной, можно было обойтись без помощи супергероев...  Супермен, Бэтмен, Чудо-женщина, Зеленый Фонарь, Флэш, Аквамен, Киборг... Пусть они еще неопытные, дерзкие и самонадеянные, каждый из них – могучая сила, способная противостоять злу. Но чтобы защитить нашу планету от инопланетного вторжения, им придется объединиться. И тогда они станут… Лигой Справедливости!  В первой книге «Начало» (в нее вошли выпуски 1–6) звездный автор Джефф Джонс и не менее звездный художник Джим Ли (известный нашим читателям по бестселлеру «Бэтмен: Тихо!»), представляют совершенно новый взгляд на вселенную DC и ее супергероев!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999152,"hdCover":""},{"id":"098932f","title":"Бэтмен. Тихо!","author":"Скотт Уильямс,Джеф Лоэб,Джим Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002054468/140/56f2/__Betmen._Tiho.jpg","isbn":"978-5-389-04715-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2014","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"«Бэтмен. Тихо!» вдохнул новую жизнь в приключения Темного Рыцаря. Рассказывать о его похождениях взялись два самых ярких таланта индустрии комиксов — Джеф Лоэб («Бэтмен. Темная победа», телесериал «Тайны Смолвиля») и Джим Ли («Дикие К.О.Т.ы», «Супермен», «Люди Икс»). Вместе они поведали читателям захватывающую историю о дружбе, доверии и предательстве длиной в целую жизнь. В это издание вошел не только весь графический роман, но и наброски, обложки выпусков, комментарии.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999151,"hdCover":""},{"id":"098932e","title":"Атака на титанов. Книга 5","author":"Хадзимэ Исаяма","type":"Манга","cover":"https://s1.livelib.ru/boocover/1002115405/140/147d/Hadzime_Isayama__Ataka_na_titanov._Kniga_5.jpg","isbn":"978-5-389-12279-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Манга"],"annotation":"Разведкорпус с помощью Эрена смог захватить  загадочную женщину-титана. Наконец бойцы узнают, кто противостоял им в облике смертоносной великанши. Не успев толком справиться с этим потрясением, люди сталкиваются с новой загадкой – тайна великих стен оказывается не менее шокирующей. И в разгар всеобщего смятения приходит известие, которое способно до основания потрясти заключенный внутри стен человеческий мир...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-04","rating":4.5,"review":"","added":9999150,"hdCover":""},{"id":"098932d","title":"Боун. Том 3. Глаза бури","author":"Джефф Смит,Дж. Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001614100/140/44e9/__Boun._Tom_3._Glaza_buri.jpg","isbn":"","publisher":"Рамона","pubDate":"2016","language":"Русский","series":"Боун","genres":["Комиксы","манга","графические романы"],"annotation":"Дела Боунов и их новых друзей становятся хуже день за днём. Луций, Смайли и Фоуни на своём пути в таверну \"Баррелхейвен\" попадают в засаду крысьих созданий.  Между тем на ферме Фоун Боун и Торн видят странные сны. Узнав об этом, бабушка Бен решает раскрыть им древние тайны и предупредить о надвигающейся угрозе. Возможно, нашим героям придётся покинуть ферму навсегда.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-03","rating":4.5,"review":"","added":9999149,"hdCover":""},{"id":"098932c","title":"Боун. Том 2. Великие коровьи бега","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001480815/140/2958/Dzheff_Smit__Boun._Tom_2._Velikie_korovi_bega.jpg","isbn":"978-5-9906529-5-8","publisher":"Рамона","pubDate":"2015","language":"Русский","series":"Боун","genres":["Комиксы","манга","графические романы"],"annotation":"Во втором томе своих удивительных приключений Боуны пытаются вернуться в родной Боунвиль. Что же может пойти не так? Практически все! Фоуни Боун рискует всем, решив быстренько навариться на ежегодно проходящих в поселке Коровьих бегах. Тем временем, все очевиднее становятся зловещие признаки назревающей войны.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-03","rating":4.5,"review":"","added":9999148,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098932b","title":"Боун. Том 1. Изгнанники Боунвиля","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001390824/140/d457/Dzheff_Smit__Boun._Tom_1._Izgnanniki_Bounvilya.jpg","isbn":"978-5-9906529-4-1","publisher":"Рамона","pubDate":"2015","language":"Русский","series":"Боун","genres":["Комиксы","манга","графические романы"],"annotation":"Откройте для себя невероятную красочную сагу о необычном герое, который должен спасти идиллическую долину от сил зла!  Изгнанная из Боунвиля троица двоюродных братьев: Фоун Боун, Фоуни Боун и Смайли Боун, разделилась и заблудилась в бескрайней неизведанной пустыне. Независимо друг от друга, они находят свой путь в таинственную, покрытую лесом долину, заселённую прекрасными и ужасными созданиями.  В конце концов, наши герои воссоединяются на ферме бабушки Бен и её бойкой внучки Торн. Однако, Боунам пока неизвестно, что против них собираются тёмные силы. Приключения только начинаются!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-03","rating":4.5,"review":"","added":9999147,"hdCover":""},{"id":"098932a","title":"Бэтмен. Книга 6. Эндшпиль","author":"Дэнни Мики,Скотт Снайдер,Грег Капулло,FCO Плаченциа","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002224951/140/8e9a/__Betmen._Kniga_6._Endshpil.jpg","isbn":"978-5-389-12474-5","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"ХА. ХА. ХА.  ОН ВЕРНУЛСЯ. И НА ЭТОТ РАЗ ОН НЕ ШУТИТ!  Бэтмен и Джокер. Темный Рыцарь и Бледный Человек. Долгие годы они противостояли друг другу. Всякий раз, когда злодей погружался во все более глубокие пучины зла, герой рвался к новым вершинам, стремясь остановить его.  Воистину, они были \"лучшими врагами\". До недавних пор.  Больше никаких игр разума. Никаких извращенных шуток. Безумный убийца, который возвел зло в ранг высокого искусства, готовится создать свой шедевр. Полностью уничтожить Бэтмена и все, что ему дорого. Он обратит против Бэтмена Лигу Справедливости. Превратит жителей Готэма в хихикающих психопатов. И это только начало. Кульминация будет ужасающей.  Бэтмен верит, что его роковой противник – всего лишь человек. Безумный, но смертный. Но что, если Джокер – это извечное зло? Сможет ли Темный Рыцарь оборвать шутку, длящуюся уже столько лет?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3,"review":"","added":9999146,"hdCover":""},{"id":"0989329","title":"Дядюшка Скрудж и Дональд Дак: Сын солнца","author":"Дон Роса","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002089873/140/1c6a/Don_Rosa__Dyadyushka_Skrudzh_i_Donald_Dak_Syn_solntsa.jpg","isbn":"978-5-17-100446-0","publisher":"АСТ, Mainstream","pubDate":"2017","language":"Русский","series":"Disney comics. Утиные истории","genres":["Комиксы","манга","графические романы"],"annotation":"Добро пожаловать в Даксбург! Встречайте Самого Богатого Селезня в мире вместе с его шумным племянником Дональдом, вундеркиндами Билли, Вилли и Дилли и коварным Флинтхартом Гломгольдом! Перед вами первый полный сборник Утиных приключений от любимого автора Дона Росы. Роса продолжает традиции легенды комиксов Disney Карла Баркса, но делает это в своём собственном стиле! Известный своим циклом «Жизнь и Времена Скруджа Макдака», Роса на протяжении двух десятков лет сочинял фантастические истории о Скрудже и Дональде. Помимо «Сына Солнца», эпической битвы за сокровища инков, в сборник также вошли истории «Денежный Поток» (об атаке Братьев Гавс на законы физики) и «Последние Сани до Доусона» с участием старого романтического увлечения Скруджа по имени Золотце Голди! Эти легендарные даксбургские истории впервые собраны в одном издании вместе с коллекцией нарисованных Росой обложек и с интересными фактами о процессе создания комиксов. Все истории расположены в хронологическом порядке. Премия Билла Фингера за выдающееся мастерство в работе над комиксами.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3.5,"review":"","added":9999145,"hdCover":""},{"id":"0989328","title":"Лига Справедливости. Книга 5. Лига несправедливости (сборник)","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002511420/140/72fa/Dzheff_Dzhons__Liga_Spravedlivosti._Kniga_5._Liga_nespravedlivosti_sbornik.jpg","isbn":"978-5-389-13084-5","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Преступный Синдикат едва не уничтожил наш мир, но Лекс Лютор возглавил сопротивление против захватчиков, прибывших с Земли-3. И теперь, оказавшись в центре всеобщего внимания, бывший заклятый враг Супермена решил во что бы то ни стало продолжать сражаться на благо человечества, став членом Лиги Справедливости.  Однако все ли намерения Лекса благие? И даже если он перешел на светлую сторону, сможет ли Лютор сработаться с теми, кого преследовал в прошлом?  Сценарист-суперзвезда Джефф Джонс («БЭТМЕН: ЗЕМЛЯ-1», «ЗЕЛЕНЫЙ ФОНАРЬ». «АКВАМЕН»), а также команда величайших художников в индустрии комиксов, включая Дуга Манки, Джейсона Фейбока, Ивана Рейса и Скотта Колинса, представляют: «ЛИГА СПРАВЕДЛИВОСТИ: ЛИГА НЕСПРАВЕДЛИВОСТИ». Это незабываемая история о врагах, союзниках и о тонкой грани между ними. В издание вошли выпуски 30–39.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4.5,"review":"","added":9999144,"hdCover":""},{"id":"0989327","title":"Лига Справедливости. Вечное зло","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002167927/140/ad2a/Dzheff_Dzhons__Liga_Spravedlivosti._Vechnoe_zlo.jpg","isbn":"978-5-389-12642-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Лига Справедливости пала. Преступный Синдикат, ее темное отражение, выследил и нейтрализовал почти всех борцов с преступностью на нашей планете. И в обстоятельствах, когда не осталось ни одного героя, спасать мир придется злодеям! Лекс Лютор ведет Капитана Холода, Черную Манту, Бизарро, Черного Адама и Синестро на битву против Синдиката. Но сумеет ли злейший враг Супермена со своими соратниками победить банду могущественных тиранов, одолевших даже Лигу Справедливости?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":5,"review":"","added":9999143,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989326","title":"Лига Справедливости. Книга 4. Вечные герои","author":"Джефф Джонс,Иван Рейс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002168053/140/8a16/__Liga_Spravedlivosti._Kniga_4._Vechnye_geroi.jpg","isbn":"978-5-389-11194-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Ультрамен. Оулмен. Супервумен. Вторгшиеся на нашу Землю из разоренной параллельной вселенной, эти беспощадные создания с помощью Тайного Общества суперзлодеев рвутся к мировому господству. Каждый из них — искаженная версия одного из героев Лиги Справедливости, заточенных ныне в огненной тюрьме, и каждый член Преступного Синдиката втайне лелеет собственный план. В этом единственная надежда Лиги и всего человечества.  Пока жестокие завоеватели сражаются с демонами своего прошлого, Вик Стоун — в прошлом обычный человек, который благодаря невероятным технологиям стал Киборгом, — должен действовать. Только Киборг может противостоять Сети — разумному компьютерному вирусу, укравшему кибертело Вика и захватившему власть над коммуникациями во всем мире.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4.5,"review":"","added":9999142,"hdCover":""},{"id":"0989325","title":"Лига справедливости. Книга 3. Трон Атлантиды (сборник)","author":"Пол Пеллетьер,Тони С. Дэниел,Джефф Джонс,Иван Рейс,Джо Прадо,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001547199/140/3ffe/__Liga_spravedlivosti._Kniga_3._Tron_Atlantidy_sbornik.jpg","isbn":"978-5-389-10767-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Прежде чем стать Акваменом, Артур Карри был правителем Атлантиды. Но суеверные атланты, с их ненавистью к обитателям суши, не смогли принять царя-получеловека.  Вступив в Лигу Справедливости, Артур покинул морское царство и передал власть над Атлантидой своему единоутробному брату Орму, Повелителю Океана. Некоторое время подводное царство поддерживало неустойчивый мир с поверхностью.  До сих пор.  Пока супергерои Земли заняты другими заботами, загадочная сила подталкивает Атлантиду и мир на поверхности к войне друг с другом. Жертв становится все больше, полномасштабное вторжение выглядит все более вероятным, и теперь только Лига Справедливости способна предотвратить кровавое столкновение, сулящее похоронить под водой добрую половину цивилизации.  Берегитесь: тот, кто владеет троном Атлантиды, решает судьбу мира…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4.5,"review":"","added":9999141,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989324","title":"Харли Квинн. Книга 2. Полная отключка","author":"Аманда Коннер,Пальмиотти Джимми","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002006706/140/937d/__Harli_Kvinn._Kniga_2._Polnaya_otklyuchka.jpg","isbn":"978-5-389-11295-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"После того, как Джокер кинул Харли Квинн — кинул буквально, в чан с хлоркой, — она решила, что тут-то ей и конец. О, как же она ошибалась!  Когда Джокер бросил ее — в смысле сбежал — безутешная Харли переехала на Кони-Айленд, чтобы вкусить от Большого Яблока и утешиться уже, в конце концов. И жизнь ее превратилась в сплошной аттракцион. Стриптиз-шоу, подпольные бойцовские клубы, ночные купания нагишом с лучшими подружками — то ли еще будет, Харли!  И правда, судьба готовит ей очередной сюрприз — да еще какой! Однажды поздней ночью возле дома Харли падает настоящая звезда — доблестная Пауэргерл, девушка с благородным сердцем и напрочь отшибленной памятью. И у нашей лиходейки тут же рождается дерзкий план: убедить могучую Пэ Гэ, что она и Харли представляют собой сногсшибательный дуэт борцов с преступностью!  Отличный план. И что могло пойти не так? Очень скоро Харли предстоит это выяснить…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":2.5,"review":"","added":9999140,"hdCover":""},{"id":"0989323","title":"Харли Квинн. Книга 1. Красотка в городе","author":"Джимми Палмиотти,Аманда Коннер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001610341/140/8a54/__Harli_Kvinn._Kniga_1._Krasotka_v_gorode.jpg","isbn":"978-5-389-10980-3","publisher":"Азбука","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В Нью-Йорке дух захватывает не только от небоскребов... По крайней мере, с тех пор, как в городе появляется Харли Квинн. Унаследовав целое здание неподалеку от знаменитого Променада, всеми любимая готэмская социопатка чувствует себя как дома в окружении фриков. Но к несчастью, о новом месте жительства Харли становится известно целой армии наемных убийц, жаждущих получить вознаграждение за ее голову. Кому же, как не Харли Квинн, принимать вызовы, брошенные бруклинским преступным миром, русскими шпионами, престарелыми гражданами и соперничающей командой роллеров? Хлопот столько, что наша героиня едва успевает перекусить парой дюжин хотдогов, что тоже своего рода вызов!  Сенсационная серия создана авторами Джимми Пальмиотти и Амандой Коннер, художником Чедом Хардином и звездной командой комикс-индустрии — Брюсом Тиммом, Джимом Ли, Адамом Хьюзом и другими. В сборник вошли выпуски с нулевого по восьмой.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3,"review":"","added":9999139,"hdCover":""},{"id":"0989322","title":"Дэдпул уничтожает Дэдпула","author":"Банн Каллен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001515929/140/fb78/Bann_Kallen__Dedpul_unichtozhaet_Dedpula.jpg","isbn":"978-5-91339-368-5","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Дэдпул открыл охоту на главную дичь: самого себя! Бесконечное числа реальностей оказывается в опасности, когда постигшая высшее самосознание версия Дэдпула решает уничтожить весь выдуманный мир, убив его прародителей - всех остальных Дэдпулов! Началась Мировая Война Уэйдов Уилсонов, и каждая версия Красного Комедианта должна выбрать сторону в кровавой бойне самой реальностью.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3,"review":"","added":9999138,"hdCover":""},{"id":"0989321","title":"Дэдпул уничтожает литературу","author":"Каллен Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001442905/140/ae7a/Kallen_Bann__Dedpul_unichtozhaet_literaturu.jpg","isbn":"978-5-91339-337-1","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Болтливый наёмник истребил всю вселенную Marvel, и теперь его цель - герои литературной классики! Капитан Ахав и Измаил огребли! Дон Кихот - Дон Капут! Томом Сойером покрасили забор! Скрудж испустил дух! Гулливеру мало не показалось! Мушкетеров уже не три! Шерлок Холмс дал свой последний обет! Рукописи не горят, а вот персонажи - очень даже! В книге собрана мини-серия Deadpool Killustrated (№1-4) сценариста Каллена Банна и художника Маттео Лолли.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3.5,"review":"","added":9999137,"hdCover":""},{"id":"0989320","title":"Испытание огнем","author":"Джеймс Дэшнер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001391688/140/d3f3/Dzhejms_Deshner__Ispytanie_ognem.jpg","isbn":"978-5-17-092413-4","publisher":"АСТ","pubDate":"2015","language":"Русский","series":"Бегущий в лабиринте","genres":["Зарубежная фантастика","Книги для подростков"],"annotation":"Лабиринт пройден, но Томасу, Терезе, Минхо и прочим глэйдерам не приходится расслабляться. Таинственное руководство ПОРОКА – секретной организации, устроившей гонки на выживание – назначает ребятам новые, смертельно опасные испытания. На сей раз их ждет переход по раскаленной пустыне и встреча с жертвами неизлечимой болезни, которые отличаются буйным нравом и непредсказуемым поведением. И словно этого недостаточно, глэйдеры оказываются в сетях предательства. Кому верить, если лучший друг ни с того ни с сего начинает тебя ненавидеть?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4,"review":"","added":9999136,"hdCover":""},{"id":"098931f","title":"Фантастическая Четверка. Том 1. Плоть и камень","author":"Рафаэль Марин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000478854/140/70c8/Rafael_Marin__Fantasticheskaya_Chetverka._Tom_1._Plot_i_kamen.jpg","isbn":"978-5-9038-9625-7","publisher":"Комикс ЛТД","pubDate":"2009","language":"Русский","series":"Лучшие сюжеты","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"Вы, конечно, знаете Фантастическую Четверку, отважных супергероев с удивительными способностями. Они - не просто команда, но еще и крепкая, дружная семья! Мистер Фантастик - гениальный ученый. Умеет растягивать свое тело, принимая любую форму по желанию! Невидимая Леди - его любящая жена, может становиться невидимкой и создавать мощные силовые поля! Человек-Факел - ее брат и штатная горячая голова команды. Может воспламеняться, метать огненные шары и раскаляться до температуры сверхновой звезды! И Существо - друг детства Мистера Фантастика, душа и совесть команды. Его тело состоит из прочного камня, под которым бьется чуткое и ранимое сердце.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3.5,"review":"","added":9999135,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098931e","title":"Человек-Паук. Том 3. Доктор Октопус","author":"Брайан Майкл Бендис, Марк Багли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000479895/140/6c8c/Brajan_Majkl_Bendis_Mark_Bagli__ChelovekPauk._Tom_3._Doktor_Oktopus.jpg","isbn":"978-5-9038-9659-2","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Человек-Паук. Лучшие сюжеты","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"«С великой силой приходит великая ответственность». Эту непростую истину довелось постичь 15-летнему Питеру Паркеру. Ради безопасности семьи и друзей он вынужден скрывать, что его второе «я» - супергерой Человек-паук. Защитив школу от злобного зеленого гоблина, он бросил вызов главарю Нью-Йоркской мафии безжалостному Кингпину и смог отправить его за решетку! Но теперь ему предстоит встретиться с врагом не только сильным, но и умным - Доктором Октопусом.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":4,"review":"","added":9999134,"hdCover":""},{"id":"098931d","title":"Гражданская война","author":"Марк Миллар,Стив МакНивен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001572180/140/1636/__Grazhdanskaya_vojna.jpg","isbn":"978-5-9908127-0-3","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После несчастного случая с участием новичков супергероев введен закон о регистрации людей со сверхспособностями. Этот закон предполагает чтобы супергерои служили государству и были квалифицированно подготовлены. Но закон о регистрации сверхлюдей разбил супергероев на два лагеря: те кто за него, во главе с Железным Человеком, и кто против - во главе с Капитаном Америка.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":3.5,"review":"","added":9999133,"hdCover":""},{"id":"098931c","title":"Доктор Стрэндж. Начало","author":"Грег Пак,Эмма Риос","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002031915/140/5daa/__Doktor_Strendzh._Nachalo.jpg","isbn":"978-5-91339-462-0","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Эта история о том, как Доктор Стрэндж и Вонг только познакомились, и, противостоя силам зла, объездили весь мир с их новой спутницей. Их ждут удивительные приключения, а также множество магии, и, конечно же, раньше Стефан был талантливым хирургом. Врагом доктора в этом комиксе может стать кто угодно. Например, Дормамму. А может, и не только он.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017","rating":2.5,"review":"","added":9999132,"hdCover":""},{"id":"098931b","title":"Люди Икс. Том 4. Геенна огненная","author":"Марк Миллар,Адам Куберт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000466513/140/d663/__Lyudi_Iks._Tom_4._Geenna_ognennaya.jpg","isbn":"978-5-903896-68-4,  978-5-903896-77-6","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Лучшие сюжеты","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"У них необычная внешность и странные способности... Но в груди каждого из Людей Икс бьется сердце настоящего героя - доброго, отважного и преданного! Персонажи комиксов \"Люди Икс\" завоевали любовь миллионов поклонников по всему миру, они - звезды трех популярных кинофильмов и множества мультсериалов. Вы держите в руках книгу с абсолютно новым сюжетом, созданным уже в XXI веке лучшими мастерами Marvel! Джину Грей мучают видения: огромная огненная птица Феникс уничтожает Землю... Пока девушка пытается понять, что это значит, в Институт Хавьера прибывает новая студентка - Китти Прайд. И буквально тут же оказывается в центре опаснейшего приключения!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2016","rating":3.5,"review":"","added":9999131,"hdCover":""},{"id":"098931a","title":"Мировая война: Халк","author":"Грег Пак,Джон Ромита-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000495533/140/a9a1/__Mirovaya_vojna_Halk.jpg","isbn":"978-5-903896-62-2","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Великие супергерои","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Самый могучий супергерой в мире комиксов Marvel, герой двух фильмов и множества компьютерных игр, наконец, предстает перед нашими читателями во всей красе! Недавно команда влиятельных супергероев \"Иллюминаты\" (Железный Человек, Мистер Фантастик, Профессор Хавьер, Черный Гром и Доктор Стрэндж) выслала Халка с Земли. На далекой планете Сакаар он нашел новых друзей и встретил свою любовь, но произошла ужасная трагедия - планета была взорвана, и Халк винит в этом \"Иллюминатов\", теперь он возвращается вместе со своими друзьями, чтобы отомстить! Такого Халка Земля еще не видела!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2015","rating":3.5,"review":"","added":9999130,"hdCover":""},{"id":"0989319","title":"Палестина","author":"Джо Сакко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001514596/140/e926/Dzho_Sakko__Palestina.jpg","isbn":"978-5-906331-27-4","publisher":"Бумкнига","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Джо Сакко- художник и журналист, обладатель многих премий в области комиксов и литературы. Его графический роман \"Палестина\" положил начало новому жанру- графическая журналистика, а имя автора стало синонимом этого направления.  В начале 90-х годов Джо Сакко провёл два месяца на Западном берегу реки Иордан и в секторе Газа, путешествовал и делал заметки. Он взял более ста интервью у палестинцев и израильтян. Результатом этой поездки и стал комикс \"Палестина\". Сакко исследует в нем политически сложную и эмоционально тяжёлую ситуацию в регионе, которая длится уже больше века.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999129,"hdCover":""},{"id":"0989318","title":"Кричащая планета. Сага Аландора","author":"Алехандро Ходоровский","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1012084112/140/2d9f/Alehandro_Hodorovskij__Krichaschaya_planeta._Saga_Alandora.jpg","isbn":"978-5-04-192855-1","publisher":"Fanzon","pubDate":"2024","language":"Русский","series":"Fanzon. Графический роман. От создателей Метабаронов","genres":["Комиксы","манга","графические романы"],"annotation":"«Кричащая планета» — сборник фантастических историй, которые публиковались в легендарном журнале Métal hurlant. Над антологией работали самые разные художники комикс-индустрии, каждый в своем собственном стиле.  «Сага Аландора» — фантастический мир бесконечной сложности и богатства, рожденный «взрывным» воображением Ходоровски и обрамленный причудливой графикой Кадело.  Астероид, обломок древней планеты, дитя ее разрушения, мчится сквозь пустоту космоса. В своем стремлении к вечности он сталкивается с обитаемыми мирами и испускает волны, которые приводят к преображениям или катастрофам. Из этих ужасающих встреч, подобно бабочкам, выпорхнувшим из своих куколок, рождаются истории… твердые и острые, как минералы, и сияющие, как кометы.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999128,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989317","title":"Метабарон. Том 2","author":"Алехандро Ходоровский,Джерри Фриссен,Валентен Сеше,Пит Вудс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008913129/140/1f93/__Metabaron._Tom_2.jpg","isbn":"978-5-04-187063-8","publisher":"Fanzon","pubDate":"2023","language":"Русский","series":"Комиксы. Современная классика. Метабароны и Техносвященники","genres":["Комиксы","манга","графические романы"],"annotation":"Возвращение в грандиозную вселенную, созданную признанным гением Алехандро Ходоровски.  Получив контроль над эпифитом, Империя становится еще более жестокой и могущественной. Для спасения собственной планеты Метабарон отправляется за запасами эпифита в параллельную вселенную, где кроме топлива встречает Метахранительницу Рину. Между ними вспыхивает страсть.  Спустя годы, Адаль и Даргона, не знающие друг о друге дети Метабарона, начинают собственную одиссею, и их пути в конце концов пересекутся…  Продолжение величественной саги о династии совершенных воинов, признанной классикой жанра и завоевавшей премию Eagle Award как лучший европейский графический роман.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999127,"hdCover":""},{"id":"0989316","title":"Глаза кошки","author":"Алехандро Ходоровский,Мёбиус","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1012669342/140/261f/__Glaza_koshki.jpg","isbn":"978-5-389-27142-5","publisher":"Азбука","pubDate":"2025","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Приключения"],"annotation":"В 1974 году Жан Жиро – настоящее имя Мёбиуса – вместе с режиссером Алехандро Ходоровски приступил к созданию фильма «Дюна». Однако проекту не суждено было выйти на экраны. Алехандро впал в глубокую депрессию и на этом фоне начал писать сюжет графического романа, к которому Жан Жиро создал потрясающие иллюстрации. Так на свет появились «Глаза кошки».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999126,"hdCover":""},{"id":"0989315","title":"Королевская кровь","author":"Алехандро Ходоровский","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1012621396/140/aef4/Alehandro_Hodorovskij__Korolevskaya_krov.jpg","isbn":"978-5-04-213304-6","publisher":"Fanzon","pubDate":"2025","language":"Русский","series":"Fanzon. Знаменитые графические романы. Подарочное издание","genres":["Графические романы"],"annotation":"Король, преданный во время войны. Трон, потерянный и захваченный. Коварная королева и безумный принц-бастард. Ужасная любовь, которой не должно быть!  Алехандро Ходоровски рассказывает мрачную историю о короле, что был предан и брошен на погибель. Его ждут годы без памяти, презрение и ненависть. Его ждет месть и возвращение трона. А также любовь, которая обернется настоящим проклятьем.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999125,"hdCover":""},{"id":"0989314","title":"Prodigy Volume 1: The Evil Earth","author":"Марк Миллар","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007042407/140/9d1e/Mark_Millar__Prodigy_Volume_1_The_Evil_Earth.jpg","isbn":"978-1534312364","publisher":"Image Comics","pubDate":"2019","language":"","series":"","genres":[],"annotation":"Edison Crane''s not content being the world''s smartest man and most successful businessman -- his brilliant mind needs constantly challenged. He''s a Nobel Prize-winning scientist, genius composer, Olympic athlete and an expert in the occult, and now international governments are calling on him to fix problems they just can''t handle.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999124,"hdCover":""},{"id":"0989313","title":"American Jesus Volume 2: The New Messiah","author":"Марк Миллар,Peter Gross","type":"Книга","cover":"https://s1.livelib.ru/boocover/1012776196/140/b5fb/__American_Jesus_Volume_2_The_New_Messiah.jpg","isbn":"1534315128","publisher":"Image Comics","pubDate":"2020","language":"","series":"","genres":[],"annotation":"AMERICAN JESUS returns with THE NEW MESSIAH. A virgin pregnancy in ''70s New York leads a young couple to flee for their lives, as evil forces close in to destroy them. Yet more bloodshed lies ahead for their daughter, Catalina, who refuses to accept her destiny as the savior of mankind.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999123,"hdCover":""},{"id":"0989312","title":"Trouble","author":"Mark Millar","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001528735/140/4456/Mark_Millar__Trouble.jpg","isbn":"978-0785150862","publisher":"MARVEL - US","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"It''s one of the most controversial stories Marvel has ever produced! When friends May and Mary take on a summer job after high school, they meet brothers Ben and Richard--and summer lovin'' ensues! Prepare for sand, sun...and lots of sex! High drama, infidelity and a pregancy! Innovative work by Mark Millar and Terry Dodson!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999122,"hdCover":""},{"id":"0989311","title":"American Jesus Volume 3: Revelation","author":"Марк Миллар,Peter Gross","type":"Книга","cover":"https://s1.livelib.ru/boocover/1012776199/140/332b/__American_Jesus_Volume_3_Revelation.jpg","isbn":"1534324992","publisher":"Image Comics","pubDate":"2023","language":"","series":"","genres":[],"annotation":"In American Jesus Volume 3, antichrist Jodie Christianson is now the President of the United States and organizing the collapse of the global economy via wars and pandemics as he ushers in the microchipping of the human population and his father''s infernal New World Order.  Christ has returned in the form of Catalina, but what chance does she have with the whole world against her?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999121,"hdCover":""},{"id":"0989310","title":"American Jesus Volume 1: Chosen","author":"Марк Миллар,Peter Gross","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007432563/140/d409/__American_Jesus_Volume_1_Chosen.jpg","isbn":"978-1607060062","publisher":"Image Comics","pubDate":"2009","language":"","series":"","genres":[],"annotation":"From the writer of the Universal hit, \"Wanted\", comes his next graphic novel on the way to becoming a feature film! \"American Jesus Volume 1: Chosen\" follows a twelve-year-old boy who suddenly discovers he''s returned as Jesus Christ. He can turn water into wine, make the crippled walk, and, perhaps, even raise the dead! How will he deal with the destiny to lead the world in a conflict thousands of years in the making?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999120,"hdCover":""}]');
